def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(1, 5):
                for b in range(1, a + 4):
                    val = ((ratio - 6.5) ** 4) * np.sin(ratio * b / (a + 0.5)) / (a * b + 1)
                    priority += val * np.cos(ratio * a * 0.7)
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 2
            for c in range(1, 6):
                priority -= np.tanh(ratio * c) * c * 0.3
        elif 4 < ratio <= 7:
            temp = 0
            for d in range(1, 10):
                factor = ((ratio - 4) ** 3) / (d ** 2 + 1)
                temp += factor * np.cos(ratio * d) * np.exp(-d / 5)
            priority = temp * np.sin(ratio) + np.log1p(ratio) * 8
            if bin_cap < item * 0.8:
                priority += np.sqrt(item * bin_cap) * 2.2
            else:
                priority -= np.tanh(bin_cap - item) * 5.5
        elif 2 <= ratio <= 4:
            s1 = 0
            s2 = 0
            for e in range(1, 20):
                s1 += ((ratio - 2) ** e) / (e + 1) * np.cos(e * ratio * 1.2)
                if e % 2 == 0:
                    s2 += ((5 - ratio) ** e) / (e * 1.5) * np.sin(e * ratio)
            priority = s1 - s2 + np.exp(-ratio / 3) * 7.3
            if i % 2 == 0:
                for f in range(1, 4):
                    priority += np.sin(f * i * ratio) * 0.5
            else:
                for g in range(1, 3):
                    priority -= np.cos(g * i / (ratio + 1)) * 0.7
        elif 0.5 <= ratio < 2:
            s = 0
            for h in range(1, 15):
                base = ((2 - ratio) ** h) / (h ** 1.8 + 0.3)
                s += base * np.tanh(ratio * h) * np.cos(h * item / (bin_cap + 1))
            if bin_cap > item * 1.5:
                penalty = np.exp(-bin_cap / (item + 0.5)) * 6
            else:
                penalty = np.sin(bin_cap * ratio) * 4.2
            priority = s + penalty + np.log(ratio + 1) * 3.1
        elif 0.2 <= ratio < 0.5:
            s = 0
            for j in range(1, 12):
                s += ((0.5 - ratio) ** j) / (j * 2) * np.sin(j * item * 0.8)
            priority = s - np.tanh(bin_cap / (item + 0.1)) * 3
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2)
            else:
                priority /= (np.sqrt(bin_cap + 0.9) + 1.5)
            for k in range(1, 5):
                priority += np.cos(k * ratio * i) * (0.5 - ratio) ** k / (k + 1)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for l in range(1, 20):
                s += ((0.2 - ratio) ** l) / (l + 1) * np.cos(l * item * 1.3)
            priority = s + 1 / (bin_cap + 2.5)
            if bin_cap < item * 0.1:
                priority += np.exp(-item * bin_cap) * 10
            else:
                priority -= np.tanh(ratio * 2) * 7
            if i % 4 == 1:
                priority += np.sin(bin_cap * ratio * 2) * 2
            else:
                priority -= np.cos(bin_cap / (ratio + 0.3)) * 1.7
        else:
            s = 0
            for m in range(1, 12):
                s += ((0.05 - ratio) ** m) / (m * 3) * np.sin(m * item * 0.7)
            priority = s + np.log1p(item + bin_cap) * 2
            if int(item * 0.5) % 7 == 0:
                priority *= 4
            else:
                priority /= 4.5
            if bin_cap < item * 0.05:
                priority += np.sqrt(item * bin_cap) * 9
            else:
                priority -= np.exp(-ratio * 3) * 6
            for n in range(1, 9):
                priority += ((0.05 - ratio) ** n) / (n + 2) * np.cos(n * item * 0.6)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for o in range(1, 5):
            if (i + o) % 4 == 0:
                priority += np.sin(ratio * (i + o) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + o) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
